/* ═══════════════════════════════════════════
   WoW CLASS DATA — icons, colors, identifiers
   Used by: character picker, class links bar,
   summary alts view, char button rendering.
═══════════════════════════════════════════ */
const CLASSES = [
  { id: 'death-knight', name: 'Death Knight', color: '#C41E3A', icon: 'data:image/png;base64,' },
  { id: 'demon-hunter', name: 'Demon Hunter', color: '#A330C9', icon: 'data:image/png;base64,' },
  { id: 'druid', name: 'Druid', color: '#FF7C0A', icon: 'data:image/png;base64,' },
  { id: 'evoker', name: 'Evoker', color: '#33937F', icon: 'data:image/png;base64,' },
  { id: 'hunter', name: 'Hunter', color: '#AAD372', icon: 'data:image/png;base64,' },
  { id: 'mage', name: 'Mage', color: '#3FC7EB', icon: 'data:image/png;base64,' },
  { id: 'monk', name: 'Monk', color: '#00A86B', icon: 'data:image/png;base64,' },
  { id: 'paladin', name: 'Paladin', color: '#F48CBA', icon: 'data:image/png;base64,' },
  { id: 'priest', name: 'Priest', color: '#FFFFFF', icon: 'data:image/png;base64,' },
  { id: 'rogue', name: 'Rogue', color: '#FFF468', icon: 'data:image/png;base64,' },
  { id: 'shaman', name: 'Shaman', color: '#0070DD', icon: 'data:image/png;base64,' },
  { id: 'warlock', name: 'Warlock', color: '#8788EE', icon: 'data:image/png;base64,' },
  { id: 'warrior', name: 'Warrior', color: '#C69B3A', icon: 'data:image/png;base64,' },
];

function classKey(charName)  { return 'wow_mn_class_' + charName; }
function loadCharClass(name) { return localStorage.getItem(classKey(name)) || ''; }
function saveCharClass(name, cls) {
  if (cls) localStorage.setItem(classKey(name), cls);
  else     localStorage.removeItem(classKey(name));
}

let _modalSelectedClass = '';

function renderClassPicker(selectedId) {
  _modalSelectedClass = selectedId || '';
  const container = document.getElementById('class-picker');
  if (!container) return;
  container.innerHTML = CLASSES.map(c => `
    <button onclick="selectClass('${c.id}')" style="
      font-family:'Cinzel',serif; font-size:11px; letter-spacing:0.06em;
      padding:4px 9px; border-radius:4px; cursor:pointer;
      border: 1.5px solid ${_modalSelectedClass === c.id ? c.color : 'rgba(255,255,255,0.1)'};
      background: ${_modalSelectedClass === c.id ? c.color + '22' : 'transparent'};
      color: ${_modalSelectedClass === c.id ? c.color : 'var(--text-secondary)'};
      transition: all 0.15s;
    "><img src="${c.icon}" style="width:18px;height:18px;vertical-align:middle;margin-right:5px;image-rendering:auto;">${c.name}</button>
  `).join('') +
  `<button onclick="selectClass('')" style="
    font-family:'Cinzel',serif; font-size:11px; letter-spacing:0.06em;
    padding:4px 9px; border-radius:4px; cursor:pointer;
    border: 1.5px solid ${!_modalSelectedClass ? 'var(--border-bright)' : 'var(--border)'};
    background: transparent; color: var(--text-muted); transition: all 0.15s;
  ">None</button>`;
}

function selectClass(id) {
  _modalSelectedClass = id;
  renderClassPicker(id);
}

function renderClassLinksBar() {
  const bar = document.getElementById('class-links-bar');
  if (!bar) return;
  const cls = loadCharClass(currentChar);
  if (!cls) { bar.style.display = 'none'; return; }
  const def = CLASSES.find(c => c.id === cls);
  if (!def) { bar.style.display = 'none'; return; }

  const slug  = cls; // e.g. 'death-knight'
  const name  = def.name.toLowerCase().replace(/\s+/g, '-'); // same as slug
  const icyUrl    = `https://www.icy-veins.com/wow/${slug}-guide`;
  const murlokUrl = `https://murlok.io/${slug}`;
  const wowheadUrl= `https://www.wowhead.com/guides/classes#${cls.replace(/-/g, '')}`;
  const blizzUrl  = `https://worldofwarcraft.blizzard.com/en-us/game/classes/${slug}`;

  const r = parseInt(def.color.slice(1,3),16);
  const g = parseInt(def.color.slice(3,5),16);
  const b = parseInt(def.color.slice(5,7),16);
  const rgba = (a) => `rgba(${r},${g},${b},${a})`;

  bar.style.cssText = `
    display:flex; align-items:center; gap:0.6rem; flex-wrap:wrap;
    padding:0.6rem 0.9rem; margin-bottom:1.25rem;
    background:${rgba(0.06)}; border:1px solid ${rgba(0.45)};
    border-radius:8px; font-size:13px;
  `;
  bar.innerHTML = `
    <span style="font-family:'Cinzel',serif;font-size:12px;letter-spacing:0.06em;color:${def.color};flex-shrink:0;">
      <img src="${def.icon}" style="width:20px;height:20px;vertical-align:middle;margin-right:5px;image-rendering:auto;">${def.name}
    </span>
    <span style="color:${rgba(0.5)};font-size:11px;">Resources:</span>
    <a href="${icyUrl}" target="_blank" rel="noopener" style="
      font-family:'Cinzel',serif;font-size:11px;letter-spacing:0.07em;
      padding:3px 10px; border-radius:4px; text-decoration:none;
      border:1px solid ${rgba(0.45)}; color:${def.color};
      background:${rgba(0.1)}; transition:all 0.2s;
    " onmouseover="this.style.background='${rgba(0.2)}'" onmouseout="this.style.background='${rgba(0.1)}'">
      📖 Icy Veins
    </a>
    <a href="${murlokUrl}" target="_blank" rel="noopener" style="
      font-family:'Cinzel',serif;font-size:11px;letter-spacing:0.07em;
      padding:3px 10px; border-radius:4px; text-decoration:none;
      border:1px solid ${rgba(0.45)}; color:${def.color};
      background:${rgba(0.1)}; transition:all 0.2s;
    " onmouseover="this.style.background='${rgba(0.2)}'" onmouseout="this.style.background='${rgba(0.1)}'">
      📊 Murlok.io
    </a>
    <a href="${wowheadUrl}" target="_blank" rel="noopener" style="
      font-family:'Cinzel',serif;font-size:11px;letter-spacing:0.07em;
      padding:3px 10px; border-radius:4px; text-decoration:none;
      border:1px solid ${rgba(0.45)}; color:${def.color};
      background:${rgba(0.1)}; transition:all 0.2s;
    " onmouseover="this.style.background='${rgba(0.2)}'" onmouseout="this.style.background='${rgba(0.1)}'">
      🔍 Wowhead
    </a>
    <a href="${blizzUrl}" target="_blank" rel="noopener" style="
      font-family:'Cinzel',serif;font-size:11px;letter-spacing:0.07em;
      padding:3px 10px; border-radius:4px; text-decoration:none;
      border:1px solid ${rgba(0.45)}; color:${def.color};
      background:${rgba(0.1)}; transition:all 0.2s;
    " onmouseover="this.style.background='${rgba(0.2)}'" onmouseout="this.style.background='${rgba(0.1)}'">
      🌐 Blizzard
    </a>`;
}
